import React, { useRef, useState, useEffect } from 'react';
import './FloatingLines.css';

const FloatingLines = ({
  linesGradient = ['#2F4BC0', '#8000ff'],
  animationSpeed = 1,
  interactive = true,
  bendRadius = 5,
  bendStrength = -0.5,
  mouseDamping = 0.05,
  parallax = true,
  parallaxStrength = 0.2,
}) => {
  const canvasRef = useRef(null);
  const linesRef = useRef([]);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    const resizeCanvas = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      initLines();
    };

    const initLines = () => {
      linesRef.current = Array.from({ length: 6 }, () => ({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        vx: (Math.random() - 0.5) * 2 * animationSpeed,
        vy: (Math.random() - 0.5) * 2 * animationSpeed,
        angle: Math.random() * Math.PI * 2,
        angularVelocity: (Math.random() - 0.5) * 0.02 * animationSpeed,
      }));
    };

    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);

    const handleMouseMove = (e) => {
      setMousePos({ x: e.clientX, y: e.clientY });
    };

    if (interactive) {
      window.addEventListener('mousemove', handleMouseMove);
    }

    let animationFrameId;
    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      const gradient = ctx.createLinearGradient(0, 0, canvas.width, canvas.height);
      gradient.addColorStop(0, linesGradient[0]);
      gradient.addColorStop(1, linesGradient[1]);

      linesRef.current.forEach((line, idx) => {
        line.angle += line.angularVelocity;
        line.x += line.vx;
        line.y += line.vy;

        if (interactive && mousePos) {
          const dx = mousePos.x - line.x;
          const dy = mousePos.y - line.y;
          const distance = Math.sqrt(dx * dx + dy * dy);
          const minDistance = 150;

          if (distance < minDistance) {
            const force = (1 - distance / minDistance) * bendStrength;
            line.vx += (dx / distance) * force * mouseDamping;
            line.vy += (dy / distance) * force * mouseDamping;
          }
        }

        // Damping
        line.vx *= 0.98;
        line.vy *= 0.98;

        // Wrap around
        if (line.x > canvas.width + 50) line.x = -50;
        if (line.x < -50) line.x = canvas.width + 50;
        if (line.y > canvas.height + 50) line.y = -50;
        if (line.y < -50) line.y = canvas.height + 50;

        // Parallax effect
        const parallaxOffset = parallax
          ? Math.sin(Date.now() * 0.001 + idx) * parallaxStrength +
            Math.cos(Date.now() * 0.0008 + idx) * parallaxStrength
          : 0;

        const endX = line.x + Math.cos(line.angle) * 80 + parallaxOffset;
        const endY = line.y + Math.sin(line.angle) * 80 + parallaxOffset;

        // Draw triple-layer glow
        ctx.strokeStyle = gradient;

        // Layer 1: Outer glow
        ctx.lineWidth = 8;
        ctx.globalAlpha = 0.15;
        ctx.beginPath();
        ctx.moveTo(line.x, line.y);
        ctx.lineTo(endX, endY);
        ctx.stroke();

        // Layer 2: Mid glow
        ctx.lineWidth = 4;
        ctx.globalAlpha = 0.35;
        ctx.beginPath();
        ctx.moveTo(line.x, line.y);
        ctx.lineTo(endX, endY);
        ctx.stroke();

        // Layer 3: Main line
        ctx.lineWidth = 2;
        ctx.globalAlpha = 1;
        ctx.beginPath();
        ctx.moveTo(line.x, line.y);
        ctx.lineTo(endX, endY);
        ctx.stroke();
      });

      animationFrameId = requestAnimationFrame(animate);
    };

    animate();

    return () => {
      cancelAnimationFrame(animationFrameId);
      window.removeEventListener('resize', resizeCanvas);
      if (interactive) {
        window.removeEventListener('mousemove', handleMouseMove);
      }
    };
  }, [
    linesGradient,
    animationSpeed,
    interactive,
    bendStrength,
    mouseDamping,
    parallax,
    parallaxStrength,
    mousePos,
  ]);

  return <canvas ref={canvasRef} className="floating-lines-canvas" />;
};

export default FloatingLines;
